	@Test
	void integerRangeFiniteAnchorAllowsMoreThanSmallLiteralLimit() {
		StatementPattern weight = statementPattern("node", "weight", "w");
		ValueExpr condition = and(
				new Compare(new Var("w"), new ValueConstant(VF.createLiteral("0", XSD.INT)), Compare.CompareOp.GE),
				new Compare(new Var("w"), new ValueConstant(VF.createLiteral("40", XSD.INT)), Compare.CompareOp.LE));
		DeferredFilter filter = new DeferredFilter(condition, Set.of("w"), JoinOrderPlanner.FILTER_COST_CHEAP, 0,
				weight, Set.of(weight), null);

		GuaranteePlanOptionProvider.Analysis analysis = assertDoesNotThrow(
				() -> GuaranteePlanOptionProvider.analyze(List.of(weight), List.of(filter),
						new FortyOneIntObjectDomainStatistics()));

		BindingSetAssignment rangeAnchor = analysis.finiteAnchorOptions()
				.getFirst()
				.factors()
				.stream()
				.filter(BindingSetAssignment.class::isInstance)
				.map(BindingSetAssignment.class::cast)
				.filter(assignment -> assignment.getBindingNames().contains("w"))
				.findFirst()
				.orElseThrow(() -> new AssertionError("Expected a generated finite range anchor: "
						+ analysis.finiteAnchorOptions()));
		assertEquals(41, countBindingSets(rangeAnchor),
				"Range finite anchors should allow the provider's 256-value guard, not the 32-value literal helper");
	}

